// src/pages/WoodDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';
// THÊM MỚI: Import dữ liệu loài. Bạn cần tạo file này.
import speciesData from '../data/speciesData';

// --- COMPONENT CHÍNH ---
function WoodDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const [farmDetails, setFarmDetails] = useState(null);
  const [activities, setActivities] = useState([]);
  const [speciesOptions, setSpeciesOptions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // CẬP NHẬT: Tách state để quản lý logic mới
  const [formData, setFormData] = useState({
    speciesName: '',      // Sẽ chứa tên lâm sản cuối cùng để gửi đi
    scientificName: '',   // Sẽ chứa tên khoa học cuối cùng để gửi đi
    date: '',
    quantity: 0,
    unit: '',
    type: '',
    reason: '',
    source: '',
    destination: '',
    verifiedBy: '',
  });

  // THÊM MỚI: State để điều khiển giao diện động
  const [selectedNewSpecies, setSelectedNewSpecies] = useState(''); // Giá trị của dropdown "Đăng ký mới"
  const [isManualEntry, setIsManualEntry] = useState(false); // Trạng thái có đang nhập tay hay không
  const [oldSpecies, setOldSpecies] = useState(''); // State riêng cho dropdown cũ

  const fetchData = useCallback(async () => { /* ... giữ nguyên logic fetchData ... */ }, [farmId, token]);
  useEffect(() => { fetchData(); }, [fetchData]);

  // --- CÁC HÀM XỬ LÝ SỰ KIỆN ---

  // Hàm xử lý chung cho các ô input thông thường
  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  // Hàm riêng cho dropdown "Tên lâm sản (đã có)"
  const handleOldSpeciesChange = (e) => {
    setOldSpecies(e.target.value);
    // Khi chọn dropdown cũ, đảm bảo lựa chọn mới được xóa đi
    setSelectedNewSpecies('');
    setIsManualEntry(false);
    setFormData(prev => ({ ...prev, speciesName: e.target.value, scientificName: '' }));
  };
  
  // THÊM MỚI: Hàm xử lý riêng cho dropdown "Tên lâm sản mới"
  const handleNewSpeciesChange = (e) => {
    const value = e.target.value;
    setSelectedNewSpecies(value);

    // Khi chọn dropdown mới, xóa lựa chọn ở dropdown cũ
    setOldSpecies('');

    if (value === 'manual') {
      setIsManualEntry(true);
      setFormData(prev => ({ ...prev, speciesName: '', scientificName: '' }));
    } else if (value === '') {
      setIsManualEntry(false);
      setFormData(prev => ({ ...prev, speciesName: '', scientificName: '' }));
    } else {
      setIsManualEntry(false);
      const matched = speciesData.find(s => s.name === value);
      if (matched) {
        setFormData(prev => ({
          ...prev,
          speciesName: matched.name,
          scientificName: matched.scientificName,
        }));
      }
    }
  };
  
  const handleAddActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');

    try {
      // Logic ưu tiên: nếu dropdown mới được chọn (hoặc đang nhập tay), dùng dữ liệu mới. Nếu không, dùng dropdown cũ.
      const finalSpeciesName = selectedNewSpecies ? formData.speciesName : oldSpecies;
      
      const dataToSend = {
        ...formData,
        speciesName: finalSpeciesName,
        farm: farmId
      };
      
      const res = await axios.post(`http://localhost:10000/api/wood-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });

      // ... logic reset form ...
    } catch (err) {
      // ... logic xử lý lỗi ...
    }
  };

  return (
    <div className="form-container">
      {/* ... các phần style và hiển thị thông tin cơ sở giữ nguyên ... */}
      
      <h3>Thêm bản ghi nhập/xuất mới:</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        <div className="form-grid">
          
          {/* TRƯỜNG TÊN LÂM SẢN CŨ */}
          <div className="form-group">
            <label>Tên lâm sản (đã có):</label>
            <select name="oldSpecies" value={oldSpecies} onChange={handleOldSpeciesChange}>
              <option value="">-- Chọn lâm sản đã có --</option>
              {speciesOptions.map((species, index) => (
                <option key={index} value={species}>{species}</option>
              ))}
            </select>
          </div>

          {/* KHU VỰC ĐĂNG KÝ MỚI LÂM SẢN */}
          <div className="form-group-full-width" style={{ gridColumn: '1 / -1', border: '1px dashed #007bff', padding: '15px', borderRadius: '8px', marginTop: '10px' }}>
            <label style={{ fontWeight: 'bold', display: 'block', marginBottom: '10px', color: '#007bff' }}>
              Hoặc đăng ký mới lâm sản
            </label>
            <div className="form-grid">
              <div className="form-group">
                <label htmlFor="newSpeciesSelection">Tên lâm sản mới:</label>
                <select 
                  id="newSpeciesSelection"
                  value={selectedNewSpecies}
                  onChange={handleNewSpeciesChange}
                >
                  <option value="">-- Chọn hoặc nhập tay --</option>
                  {speciesData.map((species, index) => (
                    <option key={index} value={species.name}>{species.name}</option>
                  ))}
                  <option value="manual">--- Nhập tay... ---</option>
                </select>
              </div>

              {!isManualEntry && selectedNewSpecies && selectedNewSpecies !== 'manual' && (
                <div className="form-group">
                  <label>Tên khoa học (tự động):</label>
                  <input type="text" value={formData.scientificName} readOnly disabled />
                </div>
              )}

              {isManualEntry && (
                <>
                  <div className="form-group">
                    <label htmlFor="speciesName">Tên lâm sản (nhập tay):</label>
                    <input type="text" name="speciesName" value={formData.speciesName} onChange={handleFormChange} required />
                  </div>
                  <div className="form-group">
                    <label htmlFor="scientificName">Tên khoa học (nhập tay):</label>
                    <input type="text" name="scientificName" value={formData.scientificName} onChange={handleFormChange} />
                  </div>
                </>
              )}
            </div>
          </div>

          {/* CÁC TRƯỜNG CÒN LẠI CỦA FORM */}
          {/* ... các trường như Ngày ghi nhận, Loại giao dịch, Số lượng v.v... */}
        </div>
        <button type="submit" className="submit-button">Thêm bản ghi</button>
      </form>

      {/* ... Bảng lịch sử hoạt động và các nút khác ... */}
    </div>
  );
}

export default WoodDetail;
